begin;alter table public.ai_sales_journeys add column if not exists policy_version integer not null default 1,add column if not exists maximum_automated_stage text not null default'qualification'check(maximum_automated_stage='qualification'),add column if not exists outbound_count integer not null default 0,add column if not exists qualification_percent integer not null default 0 check(qualification_percent between 0 and 100),add column if not exists simulation_draft_id uuid references public.commercial_simulations(id)on delete set null,add column if not exists morning_handoff_required boolean not null default true,add column if not exists handed_off_at timestamptz,add column if not exists pause_reason text;create table if not exists public.nightly_broker_handoffs(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id)on delete cascade,journey_id uuid not null references public.ai_sales_journeys(id)on delete cascade,lead_id uuid not null references public.leads(id)on delete cascade,broker_id uuid not null references public.profiles(id),summary_snapshot jsonb not null,priority text not null check(priority in('normal','high','urgent')),status text not null default'pending'check(status in('pending','acknowledged','completed')),acknowledged_at timestamptz,created_at timestamptz not null default now(),unique(journey_id,status));alter table public.nightly_broker_handoffs enable row level security;create policy nightly_broker_handoffs_scope on public.nightly_broker_handoffs for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_commercial_profile(broker_id)));revoke all on public.nightly_broker_handoffs from anon;revoke insert,update,delete on public.nightly_broker_handoffs from authenticated;grant select on public.nightly_broker_handoffs to authenticated;grant all on public.nightly_broker_handoffs to service_role;
create or replace function public.acknowledge_nightly_handoff(p_actor_id uuid,p_organization_id uuid,p_handoff_id uuid)returns jsonb language plpgsql security definer set search_path=''as$$declare h public.nightly_broker_handoffs%rowtype;begin select*into h from public.nightly_broker_handoffs where id=p_handoff_id and organization_id=p_organization_id for update;if h.id is null or h.broker_id<>p_actor_id or h.status<>'pending'then raise exception'handoff_owner_only';end if;update public.nightly_broker_handoffs set status='acknowledged',acknowledged_at=now()where id=h.id;update public.ai_sales_journeys set handed_off_at=now(),morning_handoff_required=false,updated_at=now()where id=h.journey_id;return jsonb_build_object('handoffId',h.id,'acknowledged',true,'brokerId',p_actor_id);end$$;revoke all on function public.acknowledge_nightly_handoff(uuid,uuid,uuid)from public,anon,authenticated;grant execute on function public.acknowledge_nightly_handoff(uuid,uuid,uuid)to service_role;commit;
